/**
 * IWAC Visualizations — Collection Overview block (controller)
 *
 * Thin controller: fetches the precomputed JSON, composes the layout via
 * IWACVis.panels, and registers each chart with option objects built by
 * IWACVis.chartOptions. All shared DOM + chart logic lives in
 * asset/js/charts/shared/ so this file stays focused on the block's
 * specific composition.
 *
 * Data source: asset/data/collection-overview.json (generated by
 * scripts/generate_collection_overview.py).
 *
 * Panels (in render order):
 *   1. Summary cards row
 *   2. "Period covered" subtitle
 *   3. Stacked timeline by country                (wide)
 *   4. Content by country                         (horizontal bar)
 *   5. Languages represented                      (pie)
 *   6. Newspaper coverage                         (wide, bar + range)
 *   7. Most-cited entities with type tabs         (wide, bar + click)
 *   8. Collection breakdown                       (wide, treemap)
 *
 * Load order: after shared/panels.js + shared/chart-options.js.
 */
(function () {
    'use strict';

    var ns = window.IWACVis;
    if (!ns || !ns.panels || !ns.chartOptions) {
        console.warn('IWACVis collection overview: missing panels or chartOptions — check script load order');
        return;
    }
    var P = ns.panels;
    var C = ns.chartOptions;

    /* ----------------------------------------------------------------- */
    /*  Entity type ↔ i18n key mapping                                    */
    /* ----------------------------------------------------------------- */

    var ENTITY_TYPE_I18N = {
        'Personnes':            'Persons',
        'Organisations':        'Organizations',
        'Lieux':                'Places',
        'Sujets':               'Subjects',
        '\u00c9v\u00e9nements': 'Events'
    };
    var ENTITY_TYPE_ORDER = [
        'Personnes', 'Organisations', 'Lieux', 'Sujets', '\u00c9v\u00e9nements'
    ];

    /* ----------------------------------------------------------------- */
    /*  Layout composition                                                */
    /* ----------------------------------------------------------------- */

    function buildLayout(container, data) {
        container.innerHTML = '';

        var root = P.el('div', 'iwac-vis-overview-root');
        container.appendChild(root);

        var summary = data.summary || {};

        // Summary cards
        root.appendChild(P.buildSummaryCards([
            { value: summary.articles,     labelKey: 'Articles' },
            { value: summary.publications, labelKey: 'Publications' },
            { value: summary.newspapers,   labelKey: 'Newspapers' },
            { value: summary.index_entries, labelKey: 'Entities' },
            { value: summary.countries,    labelKey: 'Countries' },
            { value: summary.languages,    labelKey: 'Languages' }
        ]));

        // Period subtitle
        var subtitle = P.buildPeriodSubtitle(summary.year_min, summary.year_max);
        if (subtitle) root.appendChild(subtitle);

        // Charts grid
        var grid = P.buildChartsGrid();
        root.appendChild(grid);

        var timelinePanel  = P.buildPanel('iwac-vis-panel iwac-vis-panel--wide', P.t('Items per year, by country'));
        var countryPanel   = P.buildPanel('iwac-vis-panel', P.t('Content by country'));
        var languagePanel  = P.buildPanel('iwac-vis-panel', P.t('Languages represented'));
        var newspaperPanel = P.buildPanel('iwac-vis-panel iwac-vis-panel--wide', P.t('Newspaper coverage'));
        var entitiesPanel  = P.buildPanel('iwac-vis-panel iwac-vis-panel--wide', P.t('Most-cited entities'));
        entitiesPanel.panel.classList.add('iwac-vis-entities-panel');
        var treemapPanel   = P.buildPanel('iwac-vis-panel iwac-vis-panel--wide', P.t('Collection breakdown'));

        grid.appendChild(timelinePanel.panel);
        grid.appendChild(countryPanel.panel);
        grid.appendChild(languagePanel.panel);
        grid.appendChild(newspaperPanel.panel);
        grid.appendChild(entitiesPanel.panel);
        grid.appendChild(treemapPanel.panel);

        // Entity tabs — rendered inside the entities panel
        var tabs = P.el('div', 'iwac-vis-tabs');
        var availableTypes = ENTITY_TYPE_ORDER.filter(function (type) {
            var list = (data.top_entities && data.top_entities[type]) || [];
            return list.length > 0;
        });
        if (availableTypes.length === 0) {
            entitiesPanel.chart.appendChild(P.el('div', 'iwac-vis-empty', P.t('No data available')));
        } else {
            availableTypes.forEach(function (type, idx) {
                var btn = P.el('button', 'iwac-vis-tab', P.t(ENTITY_TYPE_I18N[type] || type));
                btn.type = 'button';
                // Use the INDEX (not the type string) as the data attribute
                // to sidestep any Unicode round-trip concerns.
                btn.dataset.entityIdx = String(idx);
                if (idx === 0) btn.classList.add('iwac-vis-tab--active');
                tabs.appendChild(btn);
            });
        }
        entitiesPanel.panel.insertBefore(tabs, entitiesPanel.chart);

        return {
            timeline:    timelinePanel.chart,
            country:     countryPanel.chart,
            language:    languagePanel.chart,
            newspaper:   newspaperPanel.chart,
            entities:    entitiesPanel.chart,
            treemap:     treemapPanel.chart,
            tabs:        tabs,
            entityTypes: availableTypes
        };
    }

    /* ----------------------------------------------------------------- */
    /*  Main controller                                                   */
    /* ----------------------------------------------------------------- */

    function initOverview(container) {
        var basePath = container.dataset.basePath || '';
        var siteBase = container.dataset.siteBase || '';
        var url = basePath + '/modules/IwacVisualizations/asset/data/collection-overview.json';

        fetch(url)
            .then(function (r) {
                if (!r.ok) throw new Error('HTTP ' + r.status);
                return r.json();
            })
            .then(function (data) {
                var h = buildLayout(container, data);

                // 1. Timeline — generator passes `countries` not `categories`
                if (data.timeline && (data.timeline.years || []).length > 0) {
                    ns.registerChart(h.timeline, function (el, chart) {
                        chart.setOption(C.timeline(data.timeline));
                    });
                } else {
                    h.timeline.appendChild(P.el('div', 'iwac-vis-empty', P.t('No data available')));
                }

                // 2. Country bar (defensive Unknown filter lives in C.horizontalBar)
                var countries = (data.countries || []).slice(0, 10);
                if (countries.length > 0) {
                    ns.registerChart(h.country, function (el, chart) {
                        chart.setOption(C.horizontalBar(countries, { nameKey: 'name', valueKey: 'total' }));
                    });
                } else {
                    h.country.appendChild(P.el('div', 'iwac-vis-empty', P.t('No data available')));
                }

                // 3. Language pie
                var languages = (data.languages || []).slice(0, 10);
                if (languages.length > 0) {
                    ns.registerChart(h.language, function (el, chart) {
                        chart.setOption(C.pie(languages, { nameKey: 'name', valueKey: 'count' }));
                    });
                } else {
                    h.language.appendChild(P.el('div', 'iwac-vis-empty', P.t('No data available')));
                }

                // 4. Newspaper coverage
                var newspapers = (data.newspapers && data.newspapers.top) || [];
                if (newspapers.length > 0) {
                    ns.registerChart(h.newspaper, function (el, chart) {
                        chart.setOption(C.newspaper(newspapers));
                    });
                } else {
                    h.newspaper.appendChild(P.el('div', 'iwac-vis-empty', P.t('No data available')));
                }

                // 5. Top entities + tabs
                if (h.entityTypes && h.entityTypes.length > 0) {
                    wireEntityTabs(h, data, siteBase);
                }

                // 6. Treemap
                if (data.treemap && (data.treemap.children || []).length > 0) {
                    ns.registerChart(h.treemap, function (el, chart) {
                        chart.setOption(C.treemap(data.treemap));
                    });
                } else {
                    h.treemap.appendChild(P.el('div', 'iwac-vis-empty', P.t('No data available')));
                }
            })
            .catch(function (err) {
                console.error('IWACVis collection overview:', err);
                container.innerHTML = '';
                container.appendChild(P.el('div', 'iwac-vis-error', P.t('Failed to load')));
            });
    }

    /**
     * Wire up the entity tabs so clicking a tab re-renders the entity
     * chart, and theme changes also pick up the currently active tab
     * via the closure-bound renderer.
     */
    function wireEntityTabs(h, data, siteBase) {
        var currentIdx = 0;

        function renderEntityChart(elNode, chart) {
            var type = h.entityTypes[currentIdx];
            var entries = (data.top_entities && data.top_entities[type]) || [];
            chart.setOption(C.entities(entries), true);
        }

        var entityChart = ns.registerChart(h.entities, renderEntityChart);

        if (entityChart) {
            entityChart.on('click', function (params) {
                var item = params.data;
                if (item && item.o_id && siteBase) {
                    window.location.href = siteBase + '/item/' + item.o_id;
                }
            });
        }

        h.tabs.addEventListener('click', function (evt) {
            var btn = evt.target.closest('[data-entity-idx]');
            if (!btn) return;
            var idx = parseInt(btn.dataset.entityIdx, 10);
            if (isNaN(idx) || idx === currentIdx) return;
            currentIdx = idx;
            h.tabs.querySelectorAll('.iwac-vis-tab').forEach(function (b, i) {
                b.classList.toggle('iwac-vis-tab--active', i === idx);
            });
            if (entityChart && !entityChart.isDisposed()) {
                renderEntityChart(h.entities, entityChart);
            }
        });
    }

    /* ----------------------------------------------------------------- */
    /*  Auto-init                                                         */
    /* ----------------------------------------------------------------- */

    function init() {
        if (typeof echarts === 'undefined') {
            console.warn('IWACVis collection overview: ECharts not loaded');
            return;
        }
        var containers = document.querySelectorAll('.iwac-vis-overview');
        for (var i = 0; i < containers.length; i++) {
            initOverview(containers[i]);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
